'use client'
import { cn, Slot, useControllableSignal, useSignals } from '@cascivo/core'
import type { KeyboardEvent, ReactNode } from 'react'
import styles from './tile.module.css'

export interface TileProps {
  /** Identifies this tile within a group. */
  value: string
  /** Controlled selected state. */
  selected?: boolean
  /** Initial selected state for uncontrolled use. */
  defaultSelected?: boolean
  /** Called with this tile's value whenever it is toggled on (or off for multi). */
  onSelect?: (value: string) => void
  /** Single = radio semantics (toggle on); multi = checkbox semantics (toggle on/off). */
  selectable?: 'single' | 'multi'
  disabled?: boolean
  /** Optional leading icon/visual. */
  icon?: ReactNode
  /** Render as the child element instead of a div (Radix-style composition). */
  asChild?: boolean
  children?: ReactNode
  className?: string
}

/**
 * A selectable card. Renders with radio (single) or checkbox (multi) semantics and toggles via
 * click or Space/Enter. Selection is controllable; `data-selected` drives the visuals via CSS.
 */
export function Tile({
  value,
  selected,
  defaultSelected,
  onSelect,
  selectable = 'single',
  disabled,
  icon,
  asChild,
  children,
  className,
}: TileProps) {
  useSignals()
  const [isSelected, setSelected] = useControllableSignal<boolean>({
    value: selected,
    defaultValue: defaultSelected ?? false,
    onChange: () => onSelect?.(value),
  })

  const toggle = (): void => {
    if (disabled) return
    // Single behaves like a radio: selecting an already-selected tile keeps it selected.
    setSelected(selectable === 'multi' ? !isSelected.value : true)
  }

  const handleKeyDown = (e: KeyboardEvent<Element>): void => {
    if (e.key === ' ' || e.key === 'Enter') {
      e.preventDefault()
      toggle()
    }
  }

  const Comp = asChild ? Slot : 'div'

  return (
    <Comp
      role={selectable === 'multi' ? 'checkbox' : 'radio'}
      aria-checked={isSelected.value}
      aria-disabled={disabled || undefined}
      tabIndex={disabled ? -1 : 0}
      data-selected={isSelected.value || undefined}
      data-disabled={disabled || undefined}
      className={cn(styles['tile'], className)}
      onClick={toggle}
      onKeyDown={handleKeyDown}
    >
      {icon && (
        <span className={styles['icon']} aria-hidden="true">
          {icon}
        </span>
      )}
      <span className={styles['body']}>{children}</span>
    </Comp>
  )
}

@layer cascivo.component {
  .tile {
    display: flex;
    gap: var(--cascivo-space-3);
    align-items: flex-start;
    padding: var(--cascivo-space-4);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-surface);
    background: var(--cascivo-color-bg);
    color: var(--cascivo-color-text);
    cursor: pointer;
    transition:
      border-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover:not([data-disabled]) {
      border-color: var(--cascivo-color-border-strong);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    &[data-selected] {
      border-color: var(--cascivo-color-accent);
      background: color-mix(in oklch, var(--cascivo-color-accent) 4%, var(--cascivo-color-bg));
    }

    &[data-disabled] {
      opacity: 0.5;
      cursor: not-allowed;
    }
  }

  .icon {
    flex: none;
    display: grid;
    place-items: center;
    inline-size: 1.5rem;
    block-size: 1.5rem;
    color: var(--cascivo-color-text-muted);
  }

  .tile[data-selected] .icon {
    color: var(--cascivo-color-accent);
  }

  .body {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
    font-size: var(--cascivo-text-sm);
  }
}
